import type { LabelHTMLAttributes } from "react";
import { forwardRef, useId } from "react";
import { clsx } from "clsx";
import { useCheckboxGroupContext } from "../CheckboxGroup";
import { Label, type LabelCustomProps } from "../Label";
import { Hint, type HintCustomProps } from "../Hint";
import { CheckboxItem, type CheckboxItemProps } from "../CheckboxItem";
import * as styles from "./Checkbox.css";

export type CheckboxLabel = Omit<LabelCustomProps, "required">;

export type CheckboxHint = HintCustomProps;

export interface CheckboxCustomProps {
  /**
   * The label configuration
   */
  label: CheckboxLabel;

  /**
   * The hint configuration (displayed below the label)
   */
  hint?: CheckboxHint;

  /**
   * Optional class applied to the root element
   */
  className?: string;
}

type CheckboxItemPropKeysToOmit = "className" | "children";

type CheckboxItemPropsSubset = Omit<
  CheckboxItemProps,
  CheckboxItemPropKeysToOmit
>;

// Props that go to the label element (excluding CheckboxItem props and custom props)
type LabelPropsToOmit =
  | keyof CheckboxCustomProps
  | keyof CheckboxItemPropsSubset;

export interface CheckboxProps
  extends
    CheckboxItemPropsSubset,
    CheckboxCustomProps,
    Omit<LabelHTMLAttributes<HTMLLabelElement>, LabelPropsToOmit> {}

const mergeIds = (...ids: Array<string | undefined>): string | undefined => {
  const filtered = ids.filter(Boolean) as string[];
  return filtered.length > 0 ? filtered.join(" ") : undefined;
};

/**
 * A checkbox with a label and optional hint text.
 *
 * Must be used inside a CheckboxGroup, which manages the selection state.
 *
 * @example
 * <CheckboxGroup value={selectedValues} onChange={setSelectedValues}>
 *   <Checkbox value="option1" label={{ children: "Option 1" }} />
 *   <Checkbox value="option2" label={{ children: "Option 2" }} hint={{ children: "Description" }} />
 * </CheckboxGroup>
 */
export const Checkbox = forwardRef<HTMLLabelElement, CheckboxProps>(
  (
    {
      // Custom props
      label,
      hint,
      className,
      // CheckboxItem props
      id,
      value,
      size,
      name,
      hideFocusRing,
      "aria-label": ariaLabel,
      "aria-describedby": ariaDescribedBy,
      "aria-labelledby": ariaLabelledBy,
      disabled = false,
      // Rest are label element props (forwarded from Slot)
      ...labelProps
    },
    ref
  ) => {
    const generatedId = useId();
    const checkboxId = id ?? generatedId;
    const labelId = `${checkboxId}-label`;
    const hintId = hint ? `${checkboxId}-hint` : undefined;

    const describedBy = mergeIds(ariaDescribedBy, hintId);
    const labelledBy = mergeIds(ariaLabelledBy, labelId);

    // Get group-level disabled state from context
    const state = useCheckboxGroupContext();
    // Combine item-level disabled with group-level disabled
    const isDisabled = disabled || state.isDisabled;

    return (
      <label
        ref={ref}
        {...labelProps}
        className={clsx(
          styles.container,
          isDisabled && styles.containerDisabled,
          className
        )}
      >
        <CheckboxItem
          id={checkboxId}
          value={value}
          disabled={disabled}
          {...(size !== undefined && { size })}
          {...(name !== undefined && { name })}
          {...(hideFocusRing !== undefined && { hideFocusRing })}
          {...(ariaLabel !== undefined && { "aria-label": ariaLabel })}
          {...(labelledBy !== undefined && { "aria-labelledby": labelledBy })}
          {...(describedBy !== undefined && {
            "aria-describedby": describedBy,
          })}
        />
        <span className={styles.textContainer}>
          <Label variant="normal" {...label} id={labelId} asChild>
            <span>{label.children}</span>
          </Label>
          {hint && <Hint {...hint} id={hintId} />}
        </span>
      </label>
    );
  }
);

Checkbox.displayName = "Checkbox";
